@startuml

skinparam packageStyle rectangle
skinparam backgroundColor #E8E8D0

package "rugged" #E8E8D0 {

  package "raster" #E8E8D0 {
    interface "Tile" as Tile {
      + interpolateElevation(φ, λ)
      + pixelIntersection(NormalizedGeodeticPoint, los, φ index, λ index)
    }
  }

  package "intersection" #E8E8D0 {
    interface "IntersectionAlgorithm" as IntersectionAlgorithm {
      + intersection(ellipsoid, position, los)
      + refineIntersection(ellipsoid, position, los, closeGuess)
    }
  }

  package "utils" #E8E8D0 {
    class "ExtendedEllipsoid" as ExtendedEllipsoid {
      + pointAtLatitude(position, los, φ, closereference)
      + pointAtLongitude(position, los, λ)
      + pointAtAltitude(position, los, h)
      + pointOnGround(position, los)
    }
    class "SpacecraftToObservedBody" as SpacecraftToObservedBody {
    }
  }

  package "api" #E8E8D0 {
    class "Rugged" as Rugged {
      + directLocation(sensorName, line)
    }
  }

  package "linesensor" #E8E8D0 {
    class "LineSensor" as LineSensor {
    }
  }

  package "mission" #E8E8D0 {
    package "specific" #E8E8D0 {
      class "UserMain" as UserMain {
      }
    }
  }

}

IntersectionAlgorithm -up-> Tile : evaluate DEM
IntersectionAlgorithm --> ExtendedEllipsoid : compute grid points crossings
Rugged -up-> IntersectionAlgorithm : delegate DEM intersection
Rugged --> ExtendedEllipsoid : convert geodetic points
Rugged --> SpacecraftToObservedBody : convert positions/directions
Rugged -down-> LineSensor : getLOS(date, pixel)
LineSensor -up-> Rugged : getDate(line)
UserMain --> Rugged

@enduml
